
import { defineComponent, ref, watch } from "vue";
import { TreeDataItem } from "ant-design-vue/es/tree/Tree";

import { getAllItem, getItemDetail } from "@/server/http/api/user";
import { toTree } from "@/utils/DGtree";
import { nanoid } from "nanoid";
export default defineComponent({
  props: ["productId", "id"],

  setup(props, ctx) {
    const treeData = ref<TreeDataItem[]>([]);
    // tree结构

    const checkedKeys = ref<string[]>([]);

    // 待用数据
    const willData = ref([]);
    // 待发送数据
    const willApiData: any = ref([]);

    const confirmLoading = ref<boolean>(false);

    watch(checkedKeys, () => {
      //console.log("checkedKeys", checkedKeys.value);
      willApiData.value = [];
      willData.value.map((val: any) => {
        let id = checkedKeys.value.find((item: any) => {
          return item == val.checkItemId;
        });
        if (id) {
          willApiData.value.push(id);
        }
      });
      // //console.log(willApiData.value);
    });
    // 弹出框
    const visible = ref<boolean>(false);

    const showModal = (productId: number) => {
      // //console.log("productId", productId);
      getAllItem(productId).then((res: any) => {
        // //console.log(res);
        if (res.data.code === 200) {
          // //console.log(toTree(res.data.data));
          // ========树结构展示========
          treeData.value = toTree(res.data.data);
          // res.data.data.map((item: any) => {
          //   res.data.data.map((val: any) => {
          //     if (item.itemPid === val.checkItemId) {
          //       Object.assign(item, {
          //         checkItemName: val.checkItemName + "⇒" + item.checkItemName,
          //       });
          //     }
          //   });
          // });
          // console.log(res.data.data);

          // ========找出最子层检测项============
          let arr: any = [];
          function sum(trees: any) {
            trees.forEach((item: any) => {
              if (item.children !== undefined) {
                sum(item.children);
              } else {
                arr.push(item);
              }
            });
          }
          sum(treeData.value);
          // console.log("待用数据", arr);
          willData.value = arr;
          // ========找出最子层检测项============
        } else {
        }
      });
      visible.value = true;
    };

    const handleOk = (e: MouseEvent) => {
      confirmLoading.value = true;

      getItemDetail(willApiData.value).then((res: any) => {
        visible.value = false;
        confirmLoading.value = false;
        if (res.data.code === 200) {
          //console.log("检测项", res);
          res.data.data.map((item: any) => {
            Object.assign(item, {
              key: item.checkItemId + "&" + nanoid(),
              times: 1,
              id: props.id,
              method: "",
              standard: "",
            });
          });

          ctx.emit("addCheckItem", { data: res.data.data, id: props.id });
        }
      });
    };
    return {
      visible,
      showModal,
      handleOk,
      confirmLoading,
      // ==========
      treeData,

      checkedKeys,
    };
  },
});
