
import {
  defineComponent,
  inject,
  onDeactivated,
  onMounted,
  onUnmounted,
  reactive,
  ref,
  toRefs,
} from "vue";
import LimitFrom from "../../../components/ATaskdelegation/Createdelegate1/LimitFrom.vue";
import SampleFromList from "../../../components/ATaskdelegation/Createdelegate1/SampleFromList.vue";
import {
  get_select_value,
  get_entrusted_unit,
} from "../../../server/http/api/user";
import bus from "../../../utils/bus";
export default defineComponent({
  name: "Createdelegate",
  components: { LimitFrom, SampleFromList },
  setup(props, ctx) {
    const current = ref<number>(0);
    const LimitFrom = ref();
    const entrustCompanyID = ref(null);
    const next = () => {
      // bus.emit("LimitFromonSubmit");
      LimitFrom.value.onSubmit();
    };
    // // // 取消订阅
    // onDeactivated(() => {
    //   bus.off("LimitFromonSubmit");
    // });
    const currentAdd = function () {
      current.value++;
    };
    const prev = () => {
      current.value--;
    };
    let data: any = reactive({
      selectDetail: {
        arrySampling: [], //取样方式
        arryUser: [], // 用户来源
        arrySeal: [], // 签章类型
        arryTeam: [], // 团队
        arryGetReport: [], // 取报告方式
        arryCheckout: [], // 检测目的
        arryEntrust: [], // 委托方式
        witnessCompany: [], // 见证单位
        arrySampleAppearance: [], // 样品外观
        entrustCompany: [], // 委托单位
      },
    });

    // 获取委托单下拉框所有信息
    get_select_value().then((res: any) => {
      if (res.data.code === 200) {
        data.selectDetail = res.data.data;
      }
    });
    onMounted(() => {
      bus.on("getselectDetail", () => {
        get_select_value().then((res: any) => {
          if (res.data.code === 200) {
            data.selectDetail = res.data.data;
          }
        });
      });
    });

    onUnmounted(() => {
      bus.off("getselectDetail");
    });
    // 获取委托单位id
    const entrustCompany_emit = (id: any) => {
      entrustCompanyID.value = id
    };

    //委托单信息
    let subLimitFrom = function () {};
    // 保存委托单+样品信息
    let subSampleFrom = function () {
      //console.log(212313123);

      bus.emit("preservation_api");
    };

    return {
      data,
      ...toRefs(data),
      current,
      stepStyle: {
        marginBottom: "60px",
        boxShadow: "0px -1px 0 0 #e8e8e8 inset",
      },
      next,
      prev,
      subLimitFrom,
      subSampleFrom,
      currentAdd,
      LimitFrom,
      entrustCompany_emit,
      entrustCompanyID
    };
  },
});
