
import { ValidateErrorEntity } from "ant-design-vue/es/form/interface";

import { defineComponent, onMounted, reactive, ref, toRaw, toRefs } from "vue";

import UploadFile from "../../upload/UploadFile.vue";
import Entrustmodel from "@/views/ProductionManagement/ATaskdelegation/notMenuPage/Createdelegate/madal/Entrustmodel.vue";
import { getHistoryData } from "@/server/http/api/user";
import moment from "moment";
import { PlusOutlined } from "@ant-design/icons-vue";
import { getTime } from "@/utils/getTime";
import { useStore } from "vuex";
interface FormState {
  // name: string;
  // region: string | undefined;
  // date1: Moment | undefined;
  // delivery: boolean;
  // type: string[];
  // resource: string;
  // desc: string;
}
export default defineComponent({
  components: {
    UploadFile,
    Entrustmodel,
    PlusOutlined,
    VNodes: (_, { attrs }) => {
      return attrs.vnodes;
    },
  },
  props: ["selectDetail"],
  emits: ["entrustCompany_emit", "currentAdd"],
  setup(props, { emit }) {
    const formRef = ref();
    const formStatePersonRef = ref();
    const store = useStore();
    const PersonOprions: any = reactive({
      witnessPersons: [],
      entrustPeoples: [],
    });
    const personModel = reactive({
      visible: false,
      type: 1,
    });
    const formStatePerson: any = reactive({
      name: "",
      phone: "",
    });
    const rulesPerson = {
      name: [
        {
          required: true,
          message: "Please input Activity name",
          trigger: "blur",
        },
      ],

      phone: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
        {
          pattern:
            /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/,
          message: "手机号不合法",
          trigger: "blur",
        },
      ],
    };
    const userInfo = JSON.parse(store.state.userInfo);
    const formState: any = reactive({
      entrustType: null, //委托方式
      samplingMethod: null, // 取样方式
      reportType: null, // 取报告方式
      projectName: null, // 工程名称
      projectPart: null, // 工程部位
      requestDate: null, // 完成时间
      isSave: "是", // 是否留样
      checkPurpose: null, // 检验目的
      reportCount: 1, // 报告份数
      entrustCompany: null, // 委托单位
      entrustPeople: null, // 委托人
      entrustPhone: null, // 联系电话
      witnessUint: null, // 见证单位
      witnessPerson: null, // 见证人
      witnessPhone: null, // 见证电话
      paymentMethod: null, // 支付方式
      paymentRecord: null, //付款记录
      sealTypes: [], // 用章类型
      // file: "", // 提供资料
      businessAcceptor: null, //业务受理人
      acceptanceDate: moment(getTime(new Date()), "YYYY-MM-DD"), //受理日期
      // team: "", //团队
      remark: null, //备注
      address: null, //地址
      addressee: null, //收件人
      mobile: null, //收件人电话
      mailbox: null, //电子邮箱
      // adress: "",
      entrustTestType: "原材检测",
    });
    onMounted(() => {
      formState.businessAcceptor = userInfo.name;
    });
    //
    let changeEntrustUint = function (name: string) {
      // 清除上次选择人
      formState.entrustPeople = "";
      formState.entrustPhone = "";
      formState.projectName = ""; // 工程名称
      formState.projectPart = ""; // 工程部位

      emit(
        "entrustCompany_emit",
        props.selectDetail.entrustCompany.find(
          (item: any) => item.label === name
        ).value
      );

      getHistoryData({
        companyName: name,
        type: "1",
      }).then((res: any) => {
        if (res.data.code === 200) {
          let { projectName, projectPart, unitData } = res.data.data;
          formState.projectName = projectName;
          formState.projectPart = projectPart;
          PersonOprions.entrustPeoples = unitData.map((item: any) => {
            return { label: item.contacts, value: item.contactWay };
          });
        }
      });
    };
    // 过滤委托人电话
    let filterperson = function (name: string) {
      formState.entrustPhone = PersonOprions.entrustPeoples.find(
        (item: any) => {
          return item.label === name;
        }
      ).value;
    };

    let changewitnessUint = function (name: string) {
      getHistoryData({
        companyName: name,
        type: "2",
      }).then((res: any) => {
        if (res.data.code === 200) {
          let { unitData } = res.data.data;
          PersonOprions.witnessPersons = unitData.map((item: any) => {
            return { label: item.contacts, value: item.contactWay };
          });
        }
      });
    };
    // 过滤见证人电话
    let filterwitnessUint = function (name: string) {
      formState.witnessPhone = PersonOprions.witnessPersons.find(
        (item: any) => {
          return item.label === name;
        }
      ).value;
    };

    const rules = {
      reportType: [
        {
          required: true,
          message: "取报告方式为必填项",
          // trigger: "change",
        },
      ],
      entrustCompany: [
        {
          required: true,
          message: "委托单位为必填项",
          // trigger: "change",
        },
      ],
      address: [
        {
          required: true,
          message: "必填项",
          // trigger: "change",
        },
      ],
      addressee: [
        {
          required: true,
          message: "必填项",
          // trigger: "change",
        },
      ],
      mobile: [
        {
          required: true,
          message: "必填项",
          // trigger: "change",
        },
      ],
      mailbox: [
        {
          required: true,
          message: "必填项",
          // trigger: "change",
        },
      ],
      businessAcceptor: [
        {
          required: true,
          message: "必填项",
          // trigger: "change",
        },
      ],
      acceptanceDate: [
        {
          required: true,
          message: "必填项",
          type: "object",

          // trigger: "change",
        },
      ],
      requestDate: [
        {
          required: true,
          message: "必填项",
          type: "object",
          // trigger: "change",
        },
      ],
      entrustTestType: [
        {
          required: true,
          message: "必填项",
        },
      ],
    };

    const onSubmit = () => {
      formRef.value
        .validate()
        .then(() => {
          // //console.log("values", formState, toRaw(formState));
          emit("currentAdd");
          // 保存待提交数据※※※※※※※※※※※※※※※※※
          localStorage.setItem(
            "willCommitLimitFrom",
            JSON.stringify(toRaw(formState))
          );
          // ※※※※※※※※※※※※※※※※※※※※※
        })
        .catch((error: ValidateErrorEntity<FormState>) => {
          //console.log("error", error);
        });
    };
    const addItemEntrustPeople = () => {
      personModel.visible = true;
      personModel.type = 1;
    };
    const addItemWitnessPerson = () => {
      personModel.visible = true;
      personModel.type = 2;
    };

    const handleOk = () => {
      switch (personModel.type) {
        case 1:
          PersonOprions.entrustPeoples.push({
            label: formStatePerson.name,
            value: formStatePerson.phone,
          });
          formState.entrustPeople = formStatePerson.name; // 委托人
          formState.entrustPhone = formStatePerson.phone; // 联系电话

          break;
        case 2:
          PersonOprions.witnessPersons.push({
            label: formStatePerson.name,
            value: formStatePerson.phone,
          });
          formState.witnessPerson = formStatePerson.name; // 见证人
          formState.witnessPhone = formStatePerson.phone; // 见证电话
          break;
        default:
          break;
      }
      personModel.visible = false;
      formStatePerson.name = "";
      formStatePerson.phone = "";
    };
    // const resetForm = () => {
    //   formRef.value.resetFields();
    // };
    return {
      formRef,
      labelCol: { style: { width: "150px" } },
      wrapperCol: { span: 14 },
      other: "",
      formState,
      rules,
      onSubmit,
      ...toRefs(PersonOprions),
      changeEntrustUint,
      filterperson,
      changewitnessUint,
      filterwitnessUint,
      addItemWitnessPerson,
      addItemEntrustPeople,
      handleOk,
      personModel,
      formStatePerson,
      formStatePersonRef,
      rulesPerson,
    };
  },
});
