
import { ref, defineComponent, reactive, toRefs } from "vue";
import { add_new_company } from "@/server/http/api/user";

import bus from "@/utils/bus";
export default defineComponent({
  props: ["type"],
  setup(props) {
    const modalText = ref<string>("Content of the modal");
    const visible = ref<boolean>(false);
    const confirmLoading = ref<boolean>(false);
    const formRef = ref();
    const rules = {
      companyName: [
        {
          required: true,
          message: "请输入",
          trigger: "blur",
        },
        { min: 1, max: 64, message: "超出限制长度", trigger: "blur" },
      ],
      // contacts: [
      //   {
      //     required: true,
      //     message: "请输入",
      //     trigger: "blur",
      //   },
      //   { min: 1, max: 64, message: "超出限制长度", trigger: "blur" },
      // ],
      // contactWay: [
      //   {
      //     required: true,
      //     message: "请输入",
      //     trigger: "blur",
      //   },
      //   {
      //     pattern:
      //       /^(13[0-9]|14[01456879]|15[0-35-9]|16[2567]|17[0-8]|18[0-9]|19[0-35-9])\d{8}$/,
      //     message: "手机号不合法",
      //     trigger: "blur",
      // },
      // ],
    };
    let data: any = reactive({
      companyName: "",
      // contacts: "",
      // contactWay: "",
      address: "",
    });
    const showModal = () => {
      visible.value = true;
    };

    const handleOk = () => {
      confirmLoading.value = true;
      formRef.value
        .validate()
        .then(() => {
          add_new_company({
            companyName: data.companyName,
            // contacts: data.contacts,
            // contactWay: data.contactWay,
            address: data.address,
            type: props.type,
          }).then((res: any) => {
            //console.log(res);
            if (res.data.code === 200) {
              // 添加单位信息后，重新更新数据
              bus.emit("getselectDetail", true);
              visible.value = false;
              confirmLoading.value = false;
            }
            confirmLoading.value = false;
          });
        })
        .catch((error: any) => {
          //console.log("error", error);
          confirmLoading.value = false;
        });
      // 添加委托单位见证单位数据

      // setTimeout(() => {}, 2000);
    };
    return {
      data,
      modalText,
      visible,
      confirmLoading,
      showModal,
      handleOk,
      rules,
      labelCol: { span: 6 },
      wrapperCol: { span: 12 },
      formRef,
    };
  },
});
