
import { cloneDeep, lowerFirst } from "lodash-es";

import { DownOutlined } from "@ant-design/icons-vue";
import {
  defineComponent,
  ref,
  UnwrapRef,
  reactive,
  toRefs,
  onMounted,
  onUnmounted,
  onDeactivated,
} from "vue";
import Checkmodel from "@/views/ProductionManagement/ATaskdelegation/notMenuPage/Createdelegate/madal/Checkmodel.vue";
import SelectJudgment from "@/views/ProductionManagement/ATaskdelegation/notMenuPage/Createdelegate/madal/SelectJudgment.vue";
import {
  getItemMethodStandard,
  getJudgeBasis,
  add_Entrust,
} from "@/server/http/api/user";

import bus from "@/utils/bus";
import { useRouter } from "vue-router";
import { useStore } from "vuex";
const columns = [
  { title: "产品名称", dataIndex: "sampleName", key: "sampleName" },
  { title: "规格等级", dataIndex: "specs", key: "specs" },
  {
    title: "判定依据",
    dataIndex: "judgment",
    key: "judgment",
    slots: { customRender: "judgment" },
  },
  { title: "批号/编号", dataIndex: "batchNumber", key: "batchNumber" },
  { title: "代表批量", dataIndex: "generation", key: "generation" },
  { title: "样品产地", dataIndex: "sampleOrigin", key: "sampleOrigin" },
  { title: "样品状态", dataIndex: "state", key: "state" },
  { title: "操作", key: "operation", slots: { customRender: "operation" } },
];

const innerColumns = [
  { title: "检测项", dataIndex: "checkItemName", key: "checkItemName" },
  { title: "单价", dataIndex: "checkPrice", key: "checkPrice" },

  {
    title: "检测方法",
    key: "method",
    width: "20%",

    slots: { customRender: "method" },
  },
  {
    title: "检测依据",
    key: "standard",
    width: "20%",
    slots: { customRender: "standard" },
  },
  {
    title: "检测样次",
    key: "times",
    width: "10%",

    slots: { customRender: "times" },
  },
  {
    title: "修改",
    dataIndex: "operation",
    width: "20%",

    slots: { customRender: "operation" },
  },
];

interface DataItem {
  key: string;
  name: string;
  age: number;
  address: string;
}

export default defineComponent({
  props: ["sampleList"],
  emits: ["selectjudgment", "delRow"],

  components: {
    DownOutlined,
    Checkmodel,
    SelectJudgment,
  },
  setup(props, { emit }) {
    const router = useRouter();
    const store = useStore();
    const dataSource: any = ref({});
    const editableData: UnwrapRef<Record<string, DataItem>> = reactive({});
    let dataInit = reactive({
      itemMethod: [],
      itemStandard: [],
    });
    const edit = (key: string, id: number, checkItemId: number) => {
      //  ===
      dataInit.itemMethod = [];
      dataInit.itemStandard = [];
      getItemMethodStandard(checkItemId).then((res: any) => {
        if (res.data.code === 200) {
          let { itemMethod, itemStandard } = res.data.data;
          dataInit.itemMethod = itemMethod;
          dataInit.itemStandard = itemStandard;
        }
      });
      // ====
      // console.log(key, id, checkItemId);

      editableData[key] = cloneDeep(
        dataSource.value[id].filter((item: any) => key === item.key)[0]
      );
    };
    const save = (key: string, id: number) => {
      Object.assign(
        dataSource.value[id].filter((item: any) => key === item.key)[0],
        editableData[key]
      );
      delete editableData[key];
    };
    const cancel = (key: string, id: number) => {
      delete editableData[key];
    };

    // 添加检测项
    function addCheckItem(options: any) {
      // console.log(options);

      dataSource.value[options.id] = options.data;
      //console.log(dataSource.value);
    }
    // 删除
    function delRow(id: number) {
      delete dataSource.value[id];
      emit("delRow", id);
    }
    // 选择检测项
    function selectjudgment(options: any) {
      emit("selectjudgment", options);
    }

    //
    let filelist: any = ref([]);
    onMounted(() => {
      bus.on("formFile", (Filelist: any) => {
        filelist.value = Filelist.value;
      });
    });
    onUnmounted(() => {
      bus.off("formFile");
    });
    // 获取委托单基本信息  +  样品信息

    function obtain() {
      // 委托单基本信息
      let basic: any = localStorage.getItem("willCommitLimitFrom");
      let basicData = JSON.parse(basic);
      // 样品信息
      let samplelist: any = [];
      //console.log("基本信息", basicData);
      // //console.log("样品信息", props.sampleList, dataSource);

      for (let key in dataSource.value) {
        //console.log(key);

        let sampleObj: any = {};
        //  找出检测项对应样品
        let sample: any = props.sampleList.find((item: any) => {
          //console.log(item);

          return item.id == key;
        });
        //console.log(key, sample);

        // 样品id
        sampleObj.id = sample.id * 1;
        // 判定依据
        sampleObj.standardFileIds = [];
        sample.judgment.forEach((item: any) => {
          sampleObj.standardFileIds.push(item.split("~")[1] * 1);
        });
        // 检测项
        sampleObj.sampleCheckItem = [];
        dataSource.value[key].forEach((item: any) => {
          sampleObj.sampleCheckItem.push({
            checkItemId: item.checkItemId,
            standardId: item.standard.split("~")[1] * 1,
            methodId: item.method.split("~")[1] * 1,
            times: item.times,
            unitPrice: item.checkPrice,
          });
        });

        // 添加样品检测项
        samplelist.push(sampleObj);
      }
      basicData.samples = samplelist;
      let Files = new FormData();
      Files.append("json", JSON.stringify(basicData));
      filelist.value.forEach((item: any) => {
        Files.append("file", item);
      });
      //console.log("样品信息", samplelist);
      add_Entrust(Files).then((res: any) => {
        //console.log("新建委托====>", res);
        if (res.data.code === 200) {
          router.replace({ name: "Taskalpub" });
          store.commit("removeRouter", "Createdelegate");
        }
      });
    }
    onMounted(() => {
      bus.on("preservation_api", () => {
        //console.log("创建委托1");
        obtain();
      });
    });

    onUnmounted(() => {
      bus.off("preservation_api");
    });

    return {
      dataSource,
      editingKey: "",
      editableData,
      edit,
      save,
      cancel,

      columns,
      innerColumns,
      addCheckItem,
      delRow,
      selectjudgment,
      ...toRefs(dataInit),
    };
  },
});
