
import {
  defineComponent,
  onMounted,
  reactive,
  ref,
  toRaw,
  toRefs,
  watch,
} from "vue";
import { get_Sample_detail } from "@/server/http/api/user";
import { getTime } from "@/utils/setData";
import { get_sample_product_name } from "@/server/http/api/user";
const columns = [
  // {
  //   title: "样品编号",
  //   dataIndex: "sampleCode",
  // },
  {
    title: "样品名称",

    dataIndex: "sampleName",
  },
  {
    title: "规格/型号",
    dataIndex: "specs",
  },
  {
    title: "批号/编号",
    dataIndex: "batchNumber",
  },
  {
    title: "生产厂家",
    dataIndex: "manufacturer",
  },
  {
    title: "收样时间",
    dataIndex: "receivedDate",
  },
  {
    title: "操作",
    dataIndex: "action",
    slots: { customRender: "action" },
  },
];
export default defineComponent({
  emits: ["addSample"],
  props: ["entrustCompanyID"],
  setup(props, { emit }) {
    // 搜索框信息
    const formState = reactive({
      productId: "",
      manufacturer: "",
      receivedDate: [],
      pageNum: 1,
      pageSize: 10,
      companyId: null,
    });
    let total = ref(10);
    const productName: any = ref([]);
    // 产品检测项
    get_sample_product_name().then((res: any) => {
      if (res.data.code === 200) {
        productName.value = res.data.data;
      }
    });
    // 列表信息
    let sampleList = ref([]);
    function search(form: any) {
      get_Sample_detail(form).then((res: any) => {
        if (res.data.code === 200) {
          sampleList.value = res.data.data.list;
          total.value = res.data.data.total;
        }
      });
    }
    watch(
      () => props.entrustCompanyID,
      (newval) => {
        formState.companyId = newval;
      }
    );

    // onMounted(() => {
    //   search(formState);
    // });
    let timer: any;
    watch(formState, (newval: any, o) => {
      //console.log(123);
      clearTimeout(timer);
      timer = setTimeout(() => {
        let form = {};
        Object.assign(form, toRaw(formState));
        if (formState.receivedDate.length > 0) {
          Object.assign(form, {
            receivedDate:
              getTime(newval.receivedDate[0]) +
              "~" +
              getTime(newval.receivedDate[1]),
          });
          search(form);
        } else {
          Object.assign(form, {
            receivedDate: null,
          });
          search(form);
        }
      }, 400);
    });

    // 添加样品
    function addSample(sampleDetail: any) {
      emit("addSample", sampleDetail);
    }
    // 弹出框
    const visible = ref<boolean>(false);
    const showModal = () => {
      visible.value = true;
    };
    const handleOk = (e: MouseEvent) => {
      //console.log(e);
      visible.value = false;
    };
    return {
      visible,
      showModal,
      handleOk,
      sampleList,
      ...toRefs(formState),
      columns,
      addSample,
      productName,
      total,
    };
  },
});
